final:
module SR_latch(  
    input wire SR_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @(SR_S or R) begin  
        if (SR_S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (!SR_S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end else if (!SR_S && !R) begin  
            // Maintain state  
            Q <= Q;  
            Qn <= Qn;  
        end else begin  
            // Invalid state  
            Q <= 1'bx;  
            Qn <= 1'bx;  
        end  
    end  
endmodule
